def levenshtein(a: String, b: String) -> Int:
    var na = a.byte_length()
    var mb = b.byte_length()
    var prev = List[Int]()
    for _i in range(mb + 1):
        prev.append(_i)
    var cur = List[Int]()
    for i in range(1, na + 1):
        cur.append(i)
        for j in range(1, mb + 1):
            var c = 0
            if String(a[byte=i - 1]) != String(b[byte=j - 1]):
                c = 1
            var t = cur[j - 1] + 1
            if prev[j] < t:
                t = prev[j]
            if c < t:
                t = c
            cur[j] = t
        var tp = List[Int]()
        for k in range(len(cur)):
            tp.append(cur[k])
        prev = tp^
    return prev[mb]

